import sailpoint.object.PolicyViolation;
   import sailpoint.object.*;
import sailpoint.api.IdentityService;
	public PolicyViolation checkApptioViolation(Identity identity){

    boolean isViolation = false; 
    boolean hasRole = false;
	
    String empType = identity.getAttribute("type");
    List assignedRoles = identity.getAssignedRoles();
    if(assignedRoles != null && !assignedRoles.isEmpty()){
     for(Bundle assignedRole : assignedRoles){
				if("ApptioApplicationAccess".equalsIgnoreCase(assignedRole.getName()))
				     {
					 hasRole=true;
					 break;
					 }
    }
    }   
     if((null!=empType)&&(!("employee".equalsIgnoreCase(empType)))&& hasRole)
			isViolation=true;
			            
              
    if(isViolation){
             PolicyViolation v = null;
		SODConstraint constraint = new SODConstraint();
		   v = new PolicyViolation();
		   v.setActive(true);
		   v.setIdentity(identity);
		   v.setPolicy(policy);
		  v.setConstraint(constraint);
		   v.setDescription("Only Employee type of users can submt request for this application");
		   v.setStatus(sailpoint.object.PolicyViolation.Status.Open);
		return v;
	}
    return null;
  }
	
	PolicyViolation v = null;
	v = checkApptioViolation(identity);
    return v;
